import './App.css';

function App() {
  return (
    <div className="min-h-screen bg-gray-100 p-8">
      <h1 className="text-3xl font-bold text-blue-600 text-center mb-4">
        ✅ Tailwind CSS is Working!
      </h1>
      <p className="text-gray-700 text-center">
        Start building your PERN stack project with Tailwind!
      </p>
      <button className="mt-4 mx-auto block bg-blue-500 hover:bg-blue-700 text-white font-bold py-2 px-4 rounded">
        Test Button
      </button>
    </div>
  );
}

export default App;
